// Action for the magnetometer (param2) of MAV_CMD_PREFLIGHT_CALIBRATION.
type PREFLIGHT_CALIBRATION_MAGNETOMETER = common.PREFLIGHT_CALIBRATION_MAGNETOMETER

const (
	// No action.
	PREFLIGHT_CALIBRATION_MAGNETOMETER_NONE PREFLIGHT_CALIBRATION_MAGNETOMETER = common.PREFLIGHT_CALIBRATION_MAGNETOMETER_NONE
	// Start magnetometer calibration.
	PREFLIGHT_CALIBRATION_MAGNETOMETER_START PREFLIGHT_CALIBRATION_MAGNETOMETER = common.PREFLIGHT_CALIBRATION_MAGNETOMETER_START
	// Force-accept the existing compass calibration as valid without re-running it. Useful after a parameter reload that cleared calibration validity flags.
	PREFLIGHT_CALIBRATION_MAGNETOMETER_FORCE_SAVE PREFLIGHT_CALIBRATION_MAGNETOMETER = common.PREFLIGHT_CALIBRATION_MAGNETOMETER_FORCE_SAVE
)
